import os

def parse_logs(log_files):
    for f in log_files:
        with open(f) as logfile:
            log_contents = logfile.read()
            for line in log_contents.split('\n'):
                if 'ERROR' in line:
                    timestamp = line.split(' ')[0]
                    msg = line.split('ERROR')[1]
                    error_log = create_error_log(timestamp, msg)

def create_error_log(timestamp, msg):
    filename = f"error_log_{timestamp}"
    with open(filename, 'w') as error_log:
        error_log.write(msg)
    os.chmod(filename, 0o766)
    return os.path.abspath(filename)

