def group_by_anagram(words):
    anagrams = {}
    for word in words:
        canonical = ''.join(sorted(word))
        if canonical not in anagrams:
            anagrams[canonical] = []
        anagrams[canonical].append(word)
    return list(anagrams.values())

def randomized_group_by_anagram(words):
    groups = group_by_anagram(words)
    random.shuffle(groups)
    return groups

