from datetime import datetime

class Contact:
    def __init__(self, name, email, last_contacted=None):
        self.name = name
        self.email = email
        self.last_contacted = last_contacted

    def _should_send_newsletter(self):
        if self.last_contacted is None:
            return True
        # If it's been more than a month since the last email, send the newsletter
        if (datetime.now() - self.last_contacted).days > 30:
            return True
        return False

    def _send_newsletter(self):
        self.last_contacted = datetime.now()
        self._send_email("This month's news...")

    def _send_email(self, content):
        print(f"Sending email to {self.email} with content: {content}")


